32	  items.reduce((groups, item) => {
33	    const group = groups.get(item.type) ?? [];
34	    return groups.set(item.type, [...group, item]);
35	  }, new Map<string, QuoteItem[]>());
36	
37	const isHighEnchantment = (item: QuoteItem): boolean =>
38	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
39	
40	const itemSurchargeRate = (item: QuoteItem): number =>
41	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
42	  (isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0) +
43	  FIRST_INSURANCE_RATE;
44	
45	const itemPremium = (item: QuoteItem): number => {
46	  const base = basePremiumForItem(item);
47	  return base + base * itemSurchargeRate(item);
48	};
49	
50	const isBlockGroup = (type: string, group: QuoteItem[]): boolean =>
51	  BLOCK_TYPES.has(type) && group.length === BLOCK_SIZE;
52	
53	const billingItems = (items: QuoteItem[]): QuoteItem[] =>
54	  [...groupByType(items)].flatMap(([type, group]) =>
55	    isBlockGroup(type, group) ? [{ type: BLOCK_TYPE }] : group,
56	  );
57	
58	const sumBy = (items: QuoteItem[], fn: (item: QuoteItem) => number): number =>
59	  items.reduce((total, item) => total + fn(item), 0);
60	
61	const loyaltyDiscount = (customer: Customer, policyBase: number): number =>
62	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
63	
64	const followUpDiscount = (quoteIndex: number, policyBase: number): number =>
65	  quoteIndex > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
66	
67	const quoteStep = (customer: Customer, quoteIndex: number) => (step: Step) => {
68	  const billables = billingItems(step.items);
69	  const policyBase = sumBy(billables, basePremiumForItem);
70	  const premiumWithSurcharges = sumBy(billables, itemPremium);
71	  return {
72	    premium:
73	      premiumWithSurcharges -
74	      loyaltyDiscount(customer, policyBase) -
75	      followUpDiscount(quoteIndex, policyBase) +
76	      PROCESSING_FEE,
77	  };
78	};
79	
80	export const runScenario = (scenario: unknown): unknown => {
81	  const { customer, steps } = scenario as Scenario;
82	  const { results } = steps.reduce(
83	    (acc, step) => ({
84	      results: [...acc.results, quoteStep(customer, acc.quoteIndex)(step)],
85	      quoteIndex: acc.quoteIndex + (step.op === "quote" ? 1 : 0),
86	    }),
87	    { results: [] as { premium: number }[], quoteIndex: 0 },
88	  );
89	  return { results };
90	};
